def _dumps(obj: object) -> str:
    return json.dumps(obj, indent=2, ensure_ascii=False) + "\n"


def codex_plugin_json() -> str:
    return _dumps(
        {
            "name": NAME,
            "version": VERSION,
            "description": "Cities2 Chief of Staff for Codex.",
            "author": AUTHOR,
            "homepage": REPO_URL,
            "repository": REPO_URL,
            "license": LICENSE,
            "keywords": KEYWORDS,
            "skills": "./skills/",
            "mcpServers": "./.mcp.json",
            "interface": {
                "displayName": DISPLAY_NAME,
                "shortDescription": "Local Cities: Skylines II mayoral analysis",
                "longDescription": (
                    "Cities2 Chief of Staff helps Codex brief the mayor using local city evidence "
                    "from Save Investigator, Cities2-DataExport, and Cities2-InfoLoomBridge when available."
                ),
                "developerName": "mayor-modder",
                "category": "Coding",
                "capabilities": ["Read", "Write"],
                "websiteURL": REPO_URL,
                "privacyPolicyURL": PRIVACY_URL,
                "termsOfServiceURL": TERMS_URL,
                "defaultPrompt": [
                    "Prepare today's mayoral briefing.",
                    "Show me the city's top priorities.",
                    "Recommend the next moves for my city.",
                ],
                "brandColor": "#1F6F78",
                "screenshots": [],
            },
        }
    )


def codex_mcp_json() -> str:
    return _dumps(
        {
            "mcpServers": {
                NAME: {
                    "command": "node",
                    "args": ["./bin/cities2-chief-of-staff-launcher.js"],
                    "cwd": ".",
                }
            }
        }
    )


def codex_marketplace_json() -> str:
    return _dumps(
        {
            "name": NAME,
            "interface": {"displayName": MARKETPLACE_DISPLAY_NAME},
            "plugins": [
                {
                    "name": NAME,
                    "source": {"source": "local", "path": "./plugins/cities2-chief-of-staff"},
                    "policy": {"installation": "AVAILABLE", "authentication": "ON_INSTALL"},
                    "category": "Coding",
                }
            ],
        }
    )


def codex_readme_md() -> str:
    return f"""<!-- Generated by chief_of_staff.plugin_packages; edit canonical sources in chief_of_staff/plugin_metadata.py, not this file. -->

# Cities2 Chief of Staff Codex plugin

This Codex plugin helps Codex turn your local Cities: Skylines II data into a
practical mayoral briefing. It bundles the Chief of Staff skill and a
plugin-local MCP server launcher.

Privacy: the project does not collect telemetry, does not phone home, and does
not send game data to the maintainers. It runs locally through your chosen
agent environment, and only that client or model provider may process prompts
and tool outputs according to your settings. See the repository `PRIVACY.md`.

Install from the shared Mayor Modder Cities2 Plugins marketplace:

```sh
codex plugin marketplace add {CATALOG_REPO}
```
"""


