@dataclass(frozen=True)
class Platform:
    key: str
    manifest_dir: str
    plugin_json: Callable[[], str]
    mcp_json: Callable[[], str]
    readme_md: Callable[[], str]
    marketplace_json: Callable[[], str]
    dist_package_root: Path
    catalog_package_root: Path
    catalog_marketplace_rel: Path


